import{_ as a,a as i,b as o,c as t}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as l,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Aggiungere un canale Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/google-drive.md","filePath":"it-IT/upload/google-drive.md","lastUpdated":1781962217000}'),c={name:"it-IT/upload/google-drive.md"};function d(p,e,g,u,h,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="aggiungere-un-canale-google-drive" tabindex="-1">Aggiungere un canale Google Drive <a class="header-anchor" href="#aggiungere-un-canale-google-drive" aria-label="Permalink to &quot;Aggiungere un canale Google Drive&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><p>Prepara questi elementi:</p><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>Account Google</td><td>Per accedere a Google Cloud e autorizzare Google Drive</td></tr><tr><td>Progetto Google Cloud</td><td>Per abilitare la Drive API e creare credenziali OAuth</td></tr><tr><td>Client OAuth 2.0</td><td>Permette a ImgBed di ottenere <code>Client ID</code>, <code>Client Secret</code> e <code>Refresh Token</code></td></tr><tr><td>Dominio ImgBed</td><td>Per l&#39;URI di redirect OAuth. Deve corrispondere al dominio che usi davvero.</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="passaggio-1-abilita-google-drive-api" tabindex="-1">Passaggio 1: abilita Google Drive API <a class="header-anchor" href="#passaggio-1-abilita-google-drive-api" aria-label="Permalink to &quot;Passaggio 1: abilita Google Drive API&quot;">​</a></h3><ol><li>Apri Google Cloud Console.</li><li>Crea un nuovo progetto o selezionane uno esistente.</li><li>Vai a <code>APIs &amp; Services</code>.</li><li>Clicca su <code>Enable APIs and Services</code>.</li><li>Cerca <code>Google Drive API</code>.</li><li>Aprila e abilitala.</li></ol><h3 id="passaggio-2-configura-la-schermata-di-consenso-oauth" tabindex="-1">Passaggio 2: configura la schermata di consenso OAuth <a class="header-anchor" href="#passaggio-2-configura-la-schermata-di-consenso-oauth" aria-label="Permalink to &quot;Passaggio 2: configura la schermata di consenso OAuth&quot;">​</a></h3><ol><li>In Google Cloud apri <code>Google Auth Platform</code>.</li><li>Completa le informazioni di base in <code>Branding</code>, come nome app, email di supporto e contatto sviluppatore.</li><li>Apri <code>Audience</code>.</li><li>Per la maggior parte delle installazioni personali self-hosted, scegli <code>External</code>.</li><li>Se scegli <code>External</code>, aggiungi in <code>Test users</code> l&#39;account Google da autorizzare.</li><li>Apri <code>Data Access</code>.</li><li>Aggiungi i permessi Google Drive richiesti.</li></ol><h3 id="passaggio-3-crea-un-client-oauth-2-0" tabindex="-1">Passaggio 3: crea un client OAuth 2.0 <a class="header-anchor" href="#passaggio-3-crea-un-client-oauth-2-0" aria-label="Permalink to &quot;Passaggio 3: crea un client OAuth 2.0&quot;">​</a></h3><ol><li>In <code>Google Auth Platform</code>, apri <code>Clients</code>.</li><li>Crea un nuovo client.</li><li>Imposta il tipo applicazione su <code>Web application</code>.</li><li>Dai al client un nome riconoscibile.</li><li>In Authorized JavaScript origins inserisci l&#39;URL ImgBed, per esempio:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>In Authorized redirect URIs inserisci:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="Crea client OAuth" loading="lazy"></p><p><img src="'+i+'" alt="Inserisci dominio e callback" loading="lazy"></p><p>Dopo la creazione copia:</p><table tabindex="0"><thead><tr><th>Valore generato</th><th>Campo ImgBed</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="passaggio-4-compila-il-canale-google-drive" tabindex="-1">Passaggio 4: compila il canale Google Drive <a class="header-anchor" href="#passaggio-4-compila-il-canale-google-drive" aria-label="Permalink to &quot;Passaggio 4: compila il canale Google Drive&quot;">​</a></h2><p>In Impostazioni di caricamento scegli <code>Google Drive</code> e compila:</p><table tabindex="0"><thead><tr><th>Campo ImgBed</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Nome canale</td><td>Un nome riconoscibile, per esempio <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID da Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret da Google Cloud</td></tr><tr><td>Refresh Token</td><td>Lascialo vuoto per ora. Lo ottieni nel passaggio successivo.</td></tr><tr><td>Directory radice</td><td>Opzionale. Default <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Inserisci dati client in ImgBed" loading="lazy"></p><h2 id="passaggio-5-ottieni-il-refresh-token" tabindex="-1">Passaggio 5: ottieni il Refresh Token <a class="header-anchor" href="#passaggio-5-ottieni-il-refresh-token" aria-label="Permalink to &quot;Passaggio 5: ottieni il Refresh Token&quot;">​</a></h2><ol><li>Clicca su <code>Get Token</code>.</li><li>Scegli l&#39;account Google da collegare.</li><li>Completa le richieste di autorizzazione.</li><li>La pagina di callback mostrerà un <code>Refresh Token</code>.</li><li>Copialo.</li><li>Torna in ImgBed e incollalo nel campo <code>Refresh Token</code>.</li></ol><p><img src="'+t+`" alt="Copia Refresh Token dopo l&#39;autorizzazione" loading="lazy"></p><p>Se in futuro cambi account Google, cambi client OAuth o la vecchia autorizzazione scade, non devi eliminare il canale. Apri la pagina di modifica e clicca su <code>Reauthorize</code>.</p><h2 id="passaggio-6-salva-il-canale" tabindex="-1">Passaggio 6: salva il canale <a class="header-anchor" href="#passaggio-6-salva-il-canale" aria-label="Permalink to &quot;Passaggio 6: salva il canale&quot;">​</a></h2><p>Quando tutti i campi sono compilati, salva il canale.</p><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apri Google Cloud</span></span>
<span class="line"><span>-&gt; Crea o seleziona un progetto</span></span>
<span class="line"><span>-&gt; Abilita Google Drive API</span></span>
<span class="line"><span>-&gt; Configura Google Auth Platform</span></span>
<span class="line"><span>-&gt; Se Audience è External, aggiungi il tuo account Google a Test users</span></span>
<span class="line"><span>-&gt; Crea un client OAuth Web application</span></span>
<span class="line"><span>-&gt; Usa https://your-domain.com/api/oauth/google/callback come redirect URI</span></span>
<span class="line"><span>-&gt; Inserisci Client ID e Client Secret in ImgBed</span></span>
<span class="line"><span>-&gt; Clicca Get Token</span></span>
<span class="line"><span>-&gt; Accedi con Google e autorizza</span></span>
<span class="line"><span>-&gt; Copia il Refresh Token dalla pagina di callback</span></span>
<span class="line"><span>-&gt; Incollalo in ImgBed e salva</span></span>
<span class="line"><span>-&gt; Carica un&#39;immagine di prova</span></span></code></pre></div><h2 id="riferimenti" tabindex="-1">Riferimenti <a class="header-anchor" href="#riferimenti" aria-label="Permalink to &quot;Riferimenti&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const C=l(c,[["render",d]]);export{f as __pageData,C as default};
